import xml.etree.ElementTree as ET
from io import BytesIO

def validate_xml(xml_file):
    try:
        # Read the file content
        with open(xml_file, 'rb') as file:
            xml_content = file.read()
        
        # Parse the XML
        root = ET.fromstring(xml_content)
        
        # Define a schema (example: validating presence of specific tags)
        required_tags = {'book', 'title', 'author'}
        missing_tags = required_tags - {tag.tag for tag in root}
        
        if missing_tags:
            raise ValueError(f"Missing tags: {', '.join(missing_tags)}")
        
        print("XML is valid.")
    
    except ET.ParseError as e:
        print(f"Invalid XML: {e}")
    except FileNotFoundError:
        print("File not found.")
    except Exception as e:
        print(f"An error occurred: {e}")

# Example usage
validate_xml('example.xml')